import java.util.*;

public class Codechef {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int t = sc.nextInt();
        while (t-- > 0) {
            int n = sc.nextInt();
            int z = sc.nextInt();
            TreeSet<Integer> ts = new TreeSet<>();
            // Using a multiset simulation with a list since Java doesn't have multiset
            List<Integer> list = new ArrayList<>();
            for (int i = 0; i < n; i++) {
                int power = sc.nextInt();
                list.add(power);
            }
            // Sort the list to simulate multiset behavior
            Collections.sort(list);

            int count = 0;
            while (z > 0 && !list.isEmpty()) {
                // Get the max element (last element in sorted list)
                int maxEle = list.get(list.size() - 1);
                z -= maxEle;
                list.remove(list.size() - 1); // remove last element
                maxEle = maxEle >> 1; // divide by 2
                if (maxEle > 0) {
                    // Insert back in correct position to maintain sorted order
                    int index = Collections.binarySearch(list, maxEle);
                    if (index < 0) {
                        index = -index - 1;
                    }
                    list.add(index, maxEle);
                }
                count++;
            }
            if (z > 0) {
                System.out.println("Evacuate");
            } else {
                System.out.println(count);
            }
        }
        sc.close();
    }
}
